#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <stdbool.h>
#include <errno.h>

#define ROWS 530480//change
// #define LINE_LENGTH 850000
#define LINE_LENGTH 2048
#define SPECIES 3//change
#define REACTIONS 6//change
// #define MAX_GROUP_SIZE 100100

#define START_GROUP 1
#define END_GROUP 104086//change to the number of classes generated by generate_reff.c
// #define END_GROUP 8302 

typedef struct {
    int* parent;
    int size;
} UnionFind;

UnionFind* init_union_find(int size) {
    UnionFind* uf = (UnionFind*)malloc(sizeof(UnionFind));
    uf->size = size;
    uf->parent = (int*)malloc(size * sizeof(int));
    
    for (int i = 0; i < size; i++) {
        uf->parent[i] = i;
    }
    return uf;
}

int find(UnionFind* uf, int x) {
    if (uf->parent[x] != x) {
        uf->parent[x] = find(uf, uf->parent[x]);
    }
    return uf->parent[x];
}

void union_elements(UnionFind* uf, int x, int y) {
    int rootX = find(uf, x);
    int rootY = find(uf, y);
    if (rootX != rootY) {
        if (rootX < rootY) {
            uf->parent[rootY] = rootX;
        } else {
            uf->parent[rootX] = rootY;
        }
    }
}

void free_union_find(UnionFind* uf) {
    if (uf) {
        free(uf->parent);
        free(uf);
    }
}


int matricesAreEqual(int x[SPECIES*REACTIONS], int y[SPECIES*REACTIONS]) {
    for (int i = 0; i < SPECIES*REACTIONS; i++) {
        if (x[i] != y[i]) {
            return 0; 
        }
    }
    return 1;
}

void changerow(int x[SPECIES*REACTIONS], int lrow[SPECIES], int x_copy[SPECIES*REACTIONS]) {
    for (int k = 0; k < REACTIONS; k++) {
        for (int j = 0; j < SPECIES; j++) {
            x_copy[k+j*REACTIONS] = x[k+lrow[j]*REACTIONS];
        }
    }   
}

int lemmafunctionEqual(int xalpha[SPECIES*REACTIONS], int yalpha[SPECIES*REACTIONS]) {   
    int lrow[6][SPECIES] = {
    {0,1,2}, {0,2,1}, {1,0,2}, {1,2,0}, {2,0,1}, {2,1,0}
};//change to all possible orders of {1,...species}
    int xalphanew[SPECIES*REACTIONS];

    for (int i = 0; i < 6; i++){
        changerow(xalpha, lrow[i], xalphanew);
        if (matricesAreEqual(xalphanew, yalpha)==1) return 1;
    }
    return 0;
}

int int_compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int compare_matrices(const int matrix1[SPECIES*REACTIONS], const int matrix2[SPECIES*REACTIONS]) {
    int i, j;
    int rows = SPECIES;
    int cols = REACTIONS;
    
    int col_counts1[REACTIONS] = {0};
    int col_counts2[REACTIONS] = {0};
    
    int row_counts1[SPECIES] = {0};
    int row_counts2[SPECIES] = {0};
    
    for (i = 0; i < rows; i++) {
        for (j = 0; j < cols; j++) {
            col_counts1[j] += matrix1[i * cols + j];
            col_counts2[j] += matrix2[i * cols + j];
            row_counts1[i] += matrix1[i * cols + j];
            row_counts2[i] += matrix2[i * cols + j];
        }
    }
    
    qsort(col_counts1, cols, sizeof(int), int_compare);
    qsort(col_counts2, cols, sizeof(int), int_compare);
    qsort(row_counts1, rows, sizeof(int), int_compare);
    qsort(row_counts2, rows, sizeof(int), int_compare);
    
    for (i = 0; i < cols; i++) {
        if (col_counts1[i] != col_counts2[i]) {
            return 0;
        }
    }
    
    for (i = 0; i < rows; i++) {
        if (row_counts1[i] != row_counts2[i]) {
            return 0;
        }
    }
    
    return 1;
}

int** read_ny_file(const char* filename, int* total_rows) {
    FILE* file = fopen(filename, "r");
    if (!file) {
        fprintf(stderr, "error: cannot open file %s: %s\n", filename, strerror(errno));
        return NULL;
    }
    
    int** data = malloc(ROWS * sizeof(int*));
    if (!data) {
        fprintf(stderr, "error: malloc\n");
        fclose(file);
        return NULL;
    }
    
    for (int i = 0; i < ROWS; i++) {
        data[i] = NULL;
    }
    
    char line[LINE_LENGTH];
    int row = 0;
    
    while (row < ROWS && fgets(line, sizeof(line), file)) {
        data[row] = malloc(SPECIES * REACTIONS * sizeof(int));
        if (!data[row]) {
            fprintf(stderr, "error: malloc data[%d]\n", row);
            break;
        }

        char* ptr = line;
        int col = 0;
        while (col < SPECIES * REACTIONS) {
            while (*ptr == ' ') ptr++;
            
            char* end;
            data[row][col] = strtol(ptr, &end, 10);
            if (ptr == end) break;
            ptr = end;
            col++;
            
            while (*ptr == ' ') ptr++;
            if (*ptr == ',') ptr++;
        }
        
        if (col != SPECIES * REACTIONS) {
            fprintf(stderr, "error: the data of the %dth row umcomplete\n", row + 1);
            free(data[row]);
            break;
        }
        
        row++;
        
    }
    
    fclose(file);
    *total_rows = row;
    
    return data;
}


void process_single_group_with_progress(int** data, int* indices, int group_size, 
                                       FILE* output_file, int group_num) {
    if (group_size == 0) return;
    
    printf("class%d: begin (number of elements: %d)\n", group_num, group_size);
    
    UnionFind* uf = init_union_find(group_size);
    
    long total_comparisons = (long)group_size * (group_size - 1) / 2;
    long comparisons_done = 0;
    clock_t group_start = clock();
    clock_t last_update = group_start;
    
    for (int i = 0; i < group_size; i++) {
        
        for (int j = i + 1; j < group_size; j++) {
            comparisons_done++;

            clock_t now = clock();
            if (comparisons_done % (total_comparisons / 1000 + 1) == 0 || 
                ((double)(now - last_update)) / CLOCKS_PER_SEC >= 2.0) {
                
                double percent = (double)comparisons_done / total_comparisons * 100;
                double elapsed = ((double)(now - group_start)) / CLOCKS_PER_SEC;
                
                printf("class%d: %.1f%%, %.1fs\r", group_num, percent, elapsed);
                fflush(stdout);
                
                last_update = now;
            }
            
            int row_i = indices[i];
            int row_j = indices[j];
            
            // if (compare_matrices(&data[row_i][0], &data[row_j][0]) == 0) {
            //     continue;
            // }
            
            if (matricesAreEqual(data[row_i], data[row_j]) || 
                lemmafunctionEqual(data[row_i], data[row_j])) {
                union_elements(uf, i, j);
                
            }
        }
    }
    

    double group_seconds = ((double)(clock() - group_start)) / CLOCKS_PER_SEC;
    printf("class%d: finish, %.1fs                  \n", group_num, group_seconds);
    

    int rep_count = 0;
    for (int i = 0; i < group_size; i++) {
        if (find(uf, i) == i) {
            fprintf(output_file, "%d\n", indices[i] + 1);
            rep_count++;
        }
    }
    
    printf("class%d: output %d representative elements\n\n", group_num, rep_count);
    
    free_union_find(uf);
}

int main() {
    clock_t program_start = clock();
    
    int total_rows = 0;
    int** data = read_ny_file("363_2-algorithm1-4.txt", &total_rows);//change to the file generated by the first code
    if (!data) {
        return EXIT_FAILURE;
    }
    
    FILE* output_file = fopen("363_2-new-binary-indices-forgbcheck.txt", "w");//change to the output file name
    if (!output_file) {
        fprintf(stderr, "error: cannot create the output file\n");
        
        for (int i = 0; i < total_rows; i++) {
            free(data[i]);
        }
        free(data);
        
        return EXIT_FAILURE;
    }
    
    FILE* jump_file = fopen("363_2-binary-jump.txt", "w");//change to the output jump file name, this file used to record the huge class
    if (!jump_file) {
        fprintf(stderr, "error: cannot create the output jump file\n");
        
        fclose(output_file);
        for (int i = 0; i < total_rows; i++) {
            free(data[i]);
        }
        free(data);
        
        return EXIT_FAILURE;
    }
    
    setbuf(output_file, NULL);
    setbuf(jump_file, NULL);
    
    FILE* reff_file = fopen("363_2-new_binary_reff_new.txt", "r");//change to the file name generated by the generate_reff.c
    if (!reff_file) {
        fprintf(stderr, "error: cannot open reff.txt\n");
        
        fclose(output_file);
        fclose(jump_file);
        for (int i = 0; i < total_rows; i++) {
            free(data[i]);
        }
        free(data);
        
        return EXIT_FAILURE;
    }
    
    char* line = NULL;      
    size_t len = 0;         
    ssize_t read;           
    int current_group = 0;
    int processed_groups = 0;
    int skipped_groups = 0;

    printf("begin: class %d to class %d\n", START_GROUP, END_GROUP);
    printf("====================================\n");

    while ((read = getline(&line, &len, reff_file)) != -1) {
        current_group++;
        
        if (current_group < START_GROUP) continue;
        if (current_group > END_GROUP) break;
        
        int count_elements = 0;
        char* ptr = line;
        
        while (*ptr != '\0' && *ptr != '\n') {
            while (*ptr == ' ') ptr++;
            if (*ptr == '\0' || *ptr == '\n') break;
            
            if (*ptr >= '0' && *ptr <= '9') {
                count_elements++;
                while (*ptr >= '0' && *ptr <= '9') ptr++;
            } else {
                ptr++;
            }
        }
        
        printf("class%d: number of elements = %d\n", current_group, count_elements);
        
        if (count_elements > 100000) {
            fprintf(jump_file, "class%d: number of elements %d (over 100 thousand, jump)\n", 
                    current_group, count_elements);
            skipped_groups++;
            continue;
        }
        
        int* indices = malloc(count_elements * sizeof(int));
        if (!indices) {
            fprintf(stderr, "error: malloc for indices in group %d\n", current_group);
            break;
        }
        
        int group_size = 0;
        ptr = line;
        
        while (*ptr != '\0' && *ptr != '\n' && group_size < count_elements) {
            while (*ptr == ' ') ptr++;
            if (*ptr == '\0' || *ptr == '\n') break;
            
            char* end;
            int value = strtol(ptr, &end, 10);
            if (ptr == end) break;
            
            indices[group_size++] = value - 1;
            ptr = end;
            
        }
        
        if (group_size != count_elements) {
            printf("error: class%d number does not match: expect%d, real%d\n", 
                current_group, count_elements, group_size);
        }
        
        processed_groups++;
        
        process_single_group_with_progress(data, indices, group_size, output_file, current_group);

        free(indices);
    }

    if (line) {
        free(line);
        line = NULL;
    }

    
    fclose(reff_file);
    fclose(output_file);
    fclose(jump_file);
    

    for (int i = 0; i < total_rows; i++) {
        free(data[i]);
    }
    free(data);

    clock_t program_end = clock();
    double total_seconds = ((double)(program_end - program_start)) / CLOCKS_PER_SEC;
    
    printf("\n====================================\n");
    printf("processed: %d classes\n", processed_groups);
    printf("jump: %d classes\n", skipped_groups);
    printf("all: %d\n", processed_groups + skipped_groups);
    printf("Time: %.1f s (about %.1f minutes)\n", total_seconds, total_seconds / 60);
    
    return 0;
}